package com.ecommerce.order.ws;

import com.ecommerce.order.ws.model.OrderItem;
import com.ecommerce.order.ws.model.OrderRequest;
import com.ecommerce.order.ws.model.OrderResponse;
import java.util.UUID;
import javax.jws.WebService;

@WebService(endpointInterface = "com.ecommerce.order.ws.OrderProcessingService",
            serviceName = "OrderProcessingServiceService",
            portName = "OrderProcessingServicePort",
            targetNamespace = "http://ws.order.ecommerce.com/")
public class OrderProcessingServiceImpl implements OrderProcessingService {

    @Override
    public OrderResponse processOrder(OrderRequest orderRequest) {
        OrderResponse response = new OrderResponse();
        double totalAmount = 0.0;

        if (orderRequest == null || orderRequest.getCustomerId() == null || orderRequest.getCustomerId().isEmpty() ||
            orderRequest.getItems() == null || orderRequest.getItems().isEmpty()) {
            response.setOrderId("N/A");
            response.setTotalAmount(0.0);
            response.setStatus("FAILED");
            response.setMessage("Invalid order request: Customer ID or items list is missing.");
            return response;
        }

        // Calculate total amount
        for (OrderItem item : orderRequest.getItems()) {
            if (item.getPrice() < 0 || item.getQuantity() < 0) {
                 response.setOrderId("N/A");
                 response.setTotalAmount(0.0);
                 response.setStatus("FAILED");
                 response.setMessage("Invalid item price or quantity: " + item.getItemId());
                 return response;
            }
            totalAmount += item.getPrice() * item.getQuantity();
        }

        // Simulate order processing logic (e.g., saving to DB, inventory update, payment gateway call)
        String orderId = UUID.randomUUID().toString(); // Generate a unique order ID
        boolean processingSuccessful = true; // Assume success for demonstration

        if (processingSuccessful) {
            response.setOrderId(orderId);
            response.setTotalAmount(totalAmount);
            response.setStatus("SUCCESS");
            response.setMessage("Order processed successfully for Customer: " + orderRequest.getCustomerId());
        } else {
            response.setOrderId("N/A");
            response.setTotalAmount(totalAmount);
            response.setStatus("FAILED");
            response.setMessage("Order processing failed for Customer: " + orderRequest.getCustomerId() + ". Please try again.");
        }

        System.out.println("Processed Order ID: " + response.getOrderId() +
                           ", Customer: " + orderRequest.getCustomerId() +
                           ", Total: " + response.getTotalAmount() +
                           ", Status: " + response.getStatus());

        return response;
    }
}
